            };
            await $c.ext.openOzReport(reportDataList[0], opts);
        // 미리보기 체크 && 다건 선택
        } else if(chb_previewCheck.getSelectedIndex().length > 0 && reportDataList.length > 1){
            let opts = {
                type:'viewer', // viewer, print, download
